```c
#include <stdio.h>
#include <stdlib.h>
#include <conio.h>
#include <time.h>

#define BOARD_SIZE 20
#define SNAKE_SPEED 10

int board[BOARD_SIZE][BOARD_SIZE];
int snake[BOARD_SIZE][BOARD_SIZE];
int snake_length = 1;
int snake_x, snake_y;
int food_x, food_y;
int score = 0;

void init_board() {
    for (int I = 0; I < BOARD_SIZE; i++) {
        for (int j = 0; j < BOARD_SIZE; j++) {
            board[i][j] = 0;
        }
    }
}

void init_snake() {
    snake_x = BOARD_SIZE / 2;
    snake_y = BOARD_SIZE / 2;
    board[snake_x][snake_y] = 2;
}

void init_food() {
    do {
        food_x = rand() % BOARD_SIZE;
        food_y = rand() % BOARD_SIZE;
    } while (board[food_x][food_y] != 0);
    board[food_x][food_y] = 1;
}

void draw_board() {
    system("cls");
    for (int I = 0; I < BOARD_SIZE; i++) {
        for (int j = 0; j < BOARD_SIZE; j++) {
            printf("%c", (board[i][j] == 0) ? ' ' : (board[i][j] == 1) ? 'o' : '*');
        }
        printf("\n");
    }
}

void move_snake(int direction) {
    int next_x, next_y;
    switch (direction) {
        case 72: // up
            next_x = snake_x - 1;
            next_y = snake_y;
            break;
        case 80: // down
            next_x = snake_x + 1;
            next_y = snake_y;
            break;
        case 75: // left
            next_x = snake_x;
            next_y = snake_y - 1;
            break;
        case 77: // right
            next_x = snake_x;
            next_y = snake_y + 1;
            break;
        default:
            return;
    }
    if (next_x < 0 || next_x >= BOARD_SIZE || next_y < 0 || next_y >= BOARD_SIZE) {
        // snake collides with walls
        printf("game over\n");
        return;
    }
    if (board[next_x][next_y] == 2) {
        // snake collides with itself
        printf("game over\n");
        return;
    }
    for (int I = 0; I < snake_length; i++) {
        if (snake[next_x][next_y] == 1) {
            // snake eats food
            score += 10;
            board[next_x][next_y] = 2;
            snake_length++;
            snake[snake_length - 1][0] = next_x;
            snake[snake_length - 1][1] = next_y;
            init_food();
        } else if (snake[next_x][next_y] == 2) {
            // snake collides with itself
            printf("game over\n");
            return;
        }
    }
    for (int I = snake_length - 1; I > 0; i--) {
        snake[i][0] = snake[i - 1][0];
        snake[i][1] = snake[i - 1][1];
    }
    snake[0][0] = next_x;
    snake[0][1] = next_y;
    board[snake_x][snake_y] = 0;
    snake_x = next_x;
    snake_y = next_y;
    board[snake_x][snake_y] = 2;
}

int main() {
    init_board();
    init_snake();
    init_food();
    srand(time(0));
    while (1) {
        draw_board();
        printf("score: %d\n", score);
        if (kbhit()) {
            char key = getch();
            if (key == 224) {
                key = getch();
                switch (key) {
                    case 72: // up
                        move_snake(72);
                        break;
                    case 80: // down
                        move_snake(80);
                        break;
                    case 75: // left
                        move_snake(75);
                        break;
                    case 77: // right
                        move_snake(77);
                        break;
                }
            }
        }
        Sleep(SNAKE_SPEED);
    }
    return 0;
}
